    } else {
        m = { payload: el };
    }
    if (i === SEQ.length - 1 && EXPECT) { m.test = TEST; m.expect = EXPECT; }
    node.send(m);
}
return null;

if (msg.prediction === undefined) { return null; }
const p = Array.isArray(msg.prediction) ? msg.prediction : [];
let arg = 0; for (let i = 1; i < p.length; i++) if (p[i] > p[arg]) arg = i;
const labels = ['healthy','imbalance','misalignment','bearing','looseness'];
const pass = (arg === 3);
const test = 'bundled bearing-fault classifier (bearing features → class 3)';
node.status({ fill: pass ? 'green' : 'red', shape: 'dot', text: (pass ? 'PASS ' : 'FAIL ') + test });
return { payload: { test: test, pass: pass, fails: pass ? [] : ['argmax=' + arg], actual: { predictedClass: labels[arg], argmax: arg } }, _result: true };

flow.set('results', {});
flow.set('errors', []);
return msg;

const res = flow.get('results') || {};
const tests = Object.keys(res).map(k => res[k]);
const passed = tests.filter(t => t.pass).length;
const failed = tests.filter(t => !t.pass);
const EXPECTED = 48;
const complete = tests.length === EXPECTED;
msg.statusCode = (failed.length === 0 && complete) ? 200 : 500;
msg.headers = { 'content-type': 'application/json' };
const errors = flow.get('errors') || [];
msg.statusCode = (failed.length === 0 && complete && errors.length === 0) ? 200 : 500;
msg.payload = {
  ok: failed.length === 0 && complete && errors.length === 0,
  expected: EXPECTED, reported: tests.length, passed: passed, failed: failed.length,
  errorCount: errors.length,
  missing: complete ? [] : ['some tests did not report (' + tests.length + '/' + EXPECTED + ')'],
  failures: failed.map(t => ({ test: t.test, fails: t.fails })),
  errors: errors,
  results: tests.map(t => ({ test: t.test, pass: t.pass, actual: t.actual })).sort((a,b)=>a.test<b.test?-1:1)
};
return msg;

const r = msg.payload;
if (!r || !r.test) return null;
const cur = flow.get('results') || {};
cur[r.test] = r;
flow.set('results', cur);
return null;

const e = msg.error || {};
const src = e.source || {};
const arr = flow.get('errors') || [];
arr.push({ node: src.name || src.id, type: src.type, message: e.message });
flow.set('errors', arr);
return null;

const errors = flow.get('errors') || [];
msg.headers = { 'content-type': 'application/json' };
msg.payload = { count: errors.length, errors: errors };
return msg;

if (msg.test && Buffer.isBuffer(msg.payload)) {
  const m = global.get('previews') || {};
  m[msg.test] = msg.payload.toString('base64');
  global.set('previews', m);
}
return null;

const m = global.get('previews') || {};
const want = (msg.req && msg.req.query && msg.req.query.test) || '';
const keys = Object.keys(m);
const key = m[want] ? want : keys.find(k => k.indexOf(want) >= 0);
if (!key) { msg.statusCode = 404; msg.headers = { 'content-type': 'application/json' }; msg.payload = { error: 'no preview', available: keys }; return msg; }
msg.statusCode = 200; msg.headers = { 'content-type': 'image/png' };
msg.payload = Buffer.from(m[key], 'base64');
return msg;

const m = global.get('previews') || {};
const keys = Object.keys(m).sort();
let cards = keys.map(k => `<figure><img src="/preview?test=${encodeURIComponent(k)}"><figcaption>${k}</figcaption></figure>`).join('');
if (!keys.length) cards = '<p>No previews yet — run <a href="/test">/test</a> first.</p>';
msg.headers = { 'content-type': 'text/html; charset=utf-8' };
msg.payload = `<!doctype html><html><head><meta charset=utf-8><title>Vision previews</title>` +
  `<style>body{background:#1e2127;color:#eee;font-family:sans-serif;margin:16px} h1{font-size:18px} ` +
  `.grid{display:flex;flex-wrap:wrap;gap:14px} figure{margin:0;background:#2b2f37;padding:8px;border-radius:8px} ` +
  `img{image-rendering:pixelated;width:200px;height:200px;object-fit:contain;background:#000;border-radius:4px} ` +
  `figcaption{font-size:12px;margin-top:6px;max-width:200px;color:#bbb}</style></head>` +
  `<body><h1>🖼️ Annotated previews (${keys.length})</h1><p><a style=color:#8ad href="/test">re-run /test</a></p>` +
  `<div class=grid>${cards}</div></body></html>`;
return msg;
